// // This module decrements the 5-bit counter on each positive clock edge and resets to 11111 on a synchronous active high reset signal.
module counter (
  input clk,
  input reset,
  output reg [4:0] count);always @(posedge clk) begin
    if (reset) count <= 5'b00000;
    else count <= count + 1;
end

endmodule
